function rowFrom(o,i){const qty=num(o,['ShipQtyPCS','ShipQtyPC','QtyShipPCS','Qty PCS','Qty','Quantity','PCS']);const unit=num(o,['SO_UnitPrice','UnitPrice','Unit Price','Price']);const line=num(o,['LineAmtBeforeDisc','Line Amount Before Disc','DetailAmt','LineAmt','Line Amount','Correct Amount','NetAmt','TotInvc','InvoiceAmt']);const amt=line||(unit*qty);const code=val(o,['SKU_Code','SKUCode','SKU Code','ItemCode','ProductCode','Product Code']);const sku=val(o,['TAS_THName','SKU_Desc','SKU Desc','ProductName','Product','ItemName','Description'])||code||'ไม่ระบุสินค้า';const ps=cleanPs(salesPs(o)||val(o,['SalespersonID','PS','PS Code'])||'ไม่ระบุ PS');const tele=teleName(o);const type=val(o,['SOTypeID','SO Type ID','Type','DocType'],'INVC');const isTele=!!tele||/tele|telesale|telesales/i.test(type);return{date:iso(val(o,['InvcDate','Invoice_Date','InvoiceDate','ShipDateAct','ShipDate','SO_Date','OrdDate','OrderDate','Date'])),inv:val(o,['InvcNbr','InvoiceNo','Invoice No','Invoice_No','BillNo','DocNo','OrderNo','SO No','SONo'])||('NO-BILL-'+(i+1)),store:val(o,['Customer Name','CustomerName','ShipName','Ship To Name','c_Name','Store','BranchName'])||'ไม่ระบุร้าน',ps,tele:tele||(/tele|telesale|telesales/i.test(type)?'Telesale':''),isTele,code,sku,brand:val(o,['TAS_Brand','Brand','GroupBrand'],'ไม่ระบุแบรนด์'),size:val(o,['TAS_SizeGroup','SizeGroup','Size Group','SKU_Size','Size'],'ไม่ระบุไซซ์'),type,qty,unit:unit||(qty&&amt?amt/qty:0),amt}}
function realTele(r){const tele=T(r.tele),ps=T(r.ps);if(!r.isTele&&!tele)return false;const kt=K(tele),kp=K(ps);if(kt&&kp&&(kt===kp||kp.includes(kt)||kt.includes(kp)))return false;return true}
function uniq(a){return[...new Set((a||[]).map(T).filter(Boolean))]}
function scope(){const psList=uniq(window.DOIT_SELECTED_PS_LIST||[]).map(cleanPs).filter(Boolean);const ps=cleanPs($('#psSelect')?.value);return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),psList:psList.length?psList:(ps?[ps]:[]),dates:uniq(window.DOIT_SELECTED_DATES||[])}}
function inScope(r){const s=scope();if(!realTele(r))return false;if(s.dates.length&&!s.dates.includes(r.date))return false;if(!s.dates.length&&s.start&&r.date<s.start)return false;if(!s.dates.length&&s.end&&r.date>s.end)return false;if(s.psList.length&&!s.psList.includes(cleanPs(r.ps)))return false;return true}
function buildBills(){const m=new Map();let qty=0,amt=0,lineCount=0;rows.forEach(r=>{if(!inScope(r))return;lineCount++;qty+=N(r.qty);amt+=N(r.amt);const k=[r.inv,r.store,r.tele,r.date].join('|');let b=m.get(k);if(!b){b={inv:T(r.inv)||'-',store:T(r.store)||'ไม่ระบุร้าน',tele:T(r.tele)||'Telesale',ps:T(r.ps),date:T(r.date),lines:[],qty:0,amt:0};m.set(k,b)}b.lines.push(r);b.qty+=N(r.qty);b.amt+=N(r.amt)});return{bills:[...m.values()].sort((a,b)=>(a.date||'').localeCompare(b.date||'')||a.store.localeCompare(b.store,'th')||a.inv.localeCompare(b.inv,'th')),qty,amt,lineCount}}
function setBtn(){const btn=$('#teleBillsBtn');if(!btn)return;btn.textContent=`บิล Telesale (${F(buildBills().bills.length)})`;btn.onclick=openDrawer}
function ensureDrawer(){if($('#teleDrawer')&&$('#teleBody'))return;const sh=document.createElement('div');sh.className='teleShade';sh.id='teleShade';const d=document.createElement('div');d.className='teleDrawer';d.id='teleDrawer';d.innerHTML='<div class="teleHead"><b>บิล Telesale: ร้านจริง / ออเดอร์จริง</b><button class="teleClose" id="teleClose" type="button">ปิด</button></div><div class="teleBody" id="teleBody"><div class="teleEmpty">ยังไม่มีข้อมูล Telesale</div></div>';document.body.append(sh,d);sh.onclick=closeDrawer;$('#teleClose').onclick=closeDrawer}
function renderDrawer(){ensureDrawer();const body=$('#teleBody'),data=buildBills(),bs=data.bills,s=scope();if(!body)return;const dateText=s.dates.length?s.dates.map(dlabel).join(', '):`${dlabel(s.start)} - ${dlabel(s.end)}`;const psText=s.psList.length?s.psList.join(', '):'ทั้งหมด';const head=`<div class="teleScope">ช่วงวันที่: ${E(dateText)} · PS: ${E(psText)}<div class="teleScopeDebug">Telesale fix v310 · แถว Telesale หลังกรอง: ${F(data.lineCount)} · Bills: ${F(bs.length)}</div></div>`;if(!bs.length){body.innerHTML=head+'<div class="teleEmpty">ไม่พบรายการ Telesale ตามวันที่/PS ที่เลือก</div>';return}body.innerHTML=head+`<div class="teleSummary"><div><b>จำนวนบิล</b><strong>${F(bs.length)}</strong></div><div><b>จำนวนชิ้น</b><strong>${F(data.qty)}</strong></div><div><b>ยอดรวม</b><strong>฿ ${B(data.amt)}</strong></div></div>`+bs.map(b=>`<section class="teleBill"><div class="teleBillHead"><div class="store">ร้าน: ${E(b.store)}</div><div class="meta">เลขบิล/ออเดอร์: <b>${E(b.inv)}</b> · วันที่: ${E(dlabel(b.date))}<br>เทเลเซลล์: ${E(b.tele)}${b.ps?' · PS: '+E(b.ps):''}</div></div><table class="teleTbl"><thead><tr><th>#</th><th>SKU</th><th>สินค้า</th><th>จำนวน</th><th>ราคา</th><th>ยอด</th></tr></thead><tbody>${b.lines.map((r,i)=>`<tr><td>${i+1}</td><td>${E(r.code||'-')}</td><td>${E(r.sku||'')}</td><td>${F(r.qty)}</td><td>${B(r.unit)}</td><td>${B(r.amt)}</td></tr>`).join('')}</tbody></table></section>`).join('')}
function openDrawer(){renderDrawer();$('#teleShade')?.classList.add('on');$('#teleDrawer')?.classList.add('on')}
function closeDrawer(){$('#teleShade')?.classList.remove('on');$('#teleDrawer')?.classList.remove('on')}
function readSheets(wb){for(const name of wb.SheetNames){const ws=wb.Sheets[name],aoa=XLSX.utils.sheet_to_json(ws,{header:1,defval:'',raw:false});for(let i=0;i<Math.min(100,aoa.length);i++){const h=(aoa[i]||[]).map(T),score=h.filter(x=>/sku|qty|pcs|ship|customer|sales|tele|invc|invoice|brand|สินค้า|ร้าน/i.test(x)).length;if(score>=3){const out=aoa.slice(i+1).map(r=>Object.fromEntries(h.map((k,j)=>[k||('c'+j),r[j]]))).map(rowFrom).filter(r=>r.qty||r.amt||r.code);if(out.length)return out}}}return[]}
async function readPivot(buf){if(!window.JSZip)return[];const zip=await JSZip.loadAsync(buf),defs=Object.keys(zip.files).filter(k=>/^xl\/pivotCache\/pivotCacheDefinition\d+\.xml$/.test(k)).sort(),recs=Object.keys(zip.files).filter(k=>/^xl\/pivotCache\/pivotCacheRecords\d+\.xml$/.test(k)).sort();for(let z=0;z<Math.min(defs.length,recs.length);z++){const df=zip.file(defs[z]),rf=zip.file(recs[z]);if(!df||!rf)continue;const doc=new DOMParser().parseFromString(await df.async('string'),'text/xml'),fields=[...doc.getElementsByTagName('cacheField')].map(cf=>{let shared=[];const si=[...cf.childNodes].find(n=>n.nodeType===1&&n.localName==='sharedItems');if(si)[...si.childNodes].forEach(ch=>{if(ch.nodeType!==1)return;let v=ch.getAttribute('v')??'';if(ch.localName==='n')v=N(v);if(ch.localName==='d')v=T(v).slice(0,10);if(ch.localName==='m')v='';shared.push(v)});return{name:cf.getAttribute('name')||'',shared}});const rtx=await rf.async('string'),out=[];let rr=/<r>([\s\S]*?)<\/r>/g,er=/<(x|n|s|d|b|m)(?:\s+[^>]*?v="([^"]*)")?[^>]*\/>/g,m,rec=0;while((m=rr.exec(rtx))){let body=m[1],em,i=0,o={};er.lastIndex=0;while((em=er.exec(body))){const k=fields[i]?.name;if(k){const tag=em[1],v=em[2];o[k]=tag==='x'?(fields[i]?.shared[N(v)]??''):(tag==='n'?N(v):(tag==='m'?'':T(v)))}i++}const r=rowFrom(o,rec++);if(r.qty||r.amt||r.code)out.push(r)}if(out.length)return out}return[]}
async function parseFile(f){if(!f||busy)return;const key=f.name+':'+f.size+':'+f.lastModified;if(key===fileKey&&rows.length){setBtn();return}busy=true;fileKey=key;try{const buf=await f.arrayBuffer();let out=await readPivot(buf);if(!out.length&&window.XLSX)out=readSheets(XLSX.read(buf,{type:'array',cellDates:true,raw:false}));rows=out;window.__doitTelesaleRows310=rows;setBtn()}catch(e){console.warn('[telesale-count-fix-v310]',e);rows=[];setBtn()}finally{busy=false}}
function bind(){const file=$('#file');if(file&&!file.dataset.tele310){file.dataset.tele310='1';file.addEventListener('change',e=>{const f=e.target.files&&e.target.files[0];setTimeout(()=>parseFile(f),300)})}['startDate','endDate','psSelect'].forEach(id=>{const el=$('#'+id);if(el&&!el.dataset.tele310){el.dataset.tele310='1';el.addEventListener('change',()=>setTimeout(()=>{setBtn();if($('#teleDrawer')?.classList.contains('on'))renderDrawer()},50))}});['doit:psChanged','doit:selectedDatesChanged','doit:scopeRendered'].forEach(ev=>document.addEventListener(ev,()=>setTimeout(()=>{setBtn();if($('#teleDrawer')?.classList.contains('on'))renderDrawer()},80)));setBtn()}
